//! Service module - manages SipClient instances, listens for IPC commands

use crate::config::{Account, Config};
use crate::ipc::{Request, Response};
use crate::rtp::codec::Codec;
use crate::sip::{AuthMethod, SipClient, SipSettings};
use anyhow::{Context, Result};
use std::collections::HashMap;
use std::net::SocketAddr;
use std::sync::Arc;
use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::Mutex;

/// Wrapper for a managed SIP client (one per account)
struct ManagedClient {
    #[allow(dead_code)]
    account: Account,
    client: Arc<Mutex<SipClient>>,
    codec: Codec,
}

/// The service that holds all managed clients and handles IPC
pub struct Service {
    clients: HashMap<String, ManagedClient>,
    control_port: u16,
}

impl Service {
    /// Create the service, initializing all accounts from config
    pub async fn new(config: &Config, control_port: u16) -> Result<Self> {
        let mut clients = HashMap::new();

        for account in &config.accounts {
            let server_addr: SocketAddr = account
                .server
                .parse()
                .context(format!("Invalid server address for '{}'", account.name))?;

            let local_addr: SocketAddr = format!("0.0.0.0:{}", account.sip_port)
                .parse()
                .context(format!("Invalid local address for '{}'", account.name))?;

            let auth_method = match account.auth_method.as_deref() {
                Some("none") | Some("None") => AuthMethod::None,
                _ => AuthMethod::Md5,
            };

            let codec = Codec::from_str(account.codec.as_deref().unwrap_or("pcmu"))
                .unwrap_or(Codec::Pcmu);

            let sip_settings = SipSettings::from_config(
                account.display_name.clone(),
                account.asserted_id.clone(),
                account.preferred_id.clone(),
                account.proxy.clone(),
                account.register_expiry,
                account.user_agent.clone(),
                account.dtmf_mode.clone(),
                account.early_media,
                account.session_timers,
            );

            let client = SipClient::new(
                server_addr,
                local_addr,
                account.username.clone(),
                account.password.clone(),
                account.domain.clone(),
                account.rtp_port_start,
                account.rtp_port_end,
                auth_method,
                sip_settings,
            )
            .await
            .context(format!("Failed to create client for '{}'", account.name))?;

            log::info!(
                "Account '{}' ready - bound to {}, RTP {}-{}",
                account.name,
                client.local_addr,
                account.rtp_port_start,
                account.rtp_port_end
            );

            clients.insert(
                account.name.clone(),
                ManagedClient {
                    account: account.clone(),
                    client: Arc::new(Mutex::new(client)),
                    codec,
                },
            );
        }

        Ok(Service {
            clients,
            control_port,
        })
    }

    /// Start the control listener - blocks until shutdown
    pub async fn run(self) -> Result<()> {
        let bind_addr = format!("127.0.0.1:{}", self.control_port);
        let listener = TcpListener::bind(&bind_addr)
            .await
            .context(format!("Failed to bind control port {}", bind_addr))?;

        let clients = Arc::new(self.clients);
        let shutdown = Arc::new(Mutex::new(false));

        println!("Service running on {} (control port {})", bind_addr, self.control_port);
        println!("Accounts: {}", {
            clients.keys().map(|s| s.as_str()).collect::<Vec<_>>().join(", ")
        });
        println!("Send 'shutdown' command to stop.");

        loop {
            if *shutdown.lock().await {
                println!("Shutting down service.");
                break;
            }

            // Use timeout so we periodically check the shutdown flag
            let accept_result = tokio::time::timeout(
                std::time::Duration::from_millis(500),
                listener.accept(),
            )
            .await;

            match accept_result {
                Ok(Ok((stream, addr))) => {
                    log::debug!("Control connection from {}", addr);
                    let clients = clients.clone();
                    let shutdown = shutdown.clone();
                    tokio::spawn(async move {
                        Self::handle_connection(stream, clients, shutdown).await;
                    });
                }
                Ok(Err(e)) => {
                    log::error!("Accept error: {}", e);
                }
                Err(_) => {
                    // Timeout - loop back to check shutdown flag
                }
            }
        }

        println!("Service stopped.");
        Ok(())
    }

    /// Handle one control connection: read request → process → send response
    async fn handle_connection(
        stream: TcpStream,
        clients: Arc<HashMap<String, ManagedClient>>,
        shutdown: Arc<Mutex<bool>>,
    ) {
        let (reader_half, mut write_half) = stream.into_split();
        let mut buf_reader = BufReader::new(reader_half);
        let mut line = String::new();

        match buf_reader.read_line(&mut line).await {
            Ok(0) => return,
            Ok(_) => {}
            Err(e) => {
                let resp = Response::fail(&format!("Read error: {}", e));
                let _ = write_half
                    .write_all(format!("{}\n", serde_json::to_string(&resp).unwrap()).as_bytes())
                    .await;
                return;
            }
        };

        let req: Request = match serde_json::from_str(line.trim()) {
            Ok(r) => r,
            Err(e) => {
                let resp = Response::fail(&format!("Invalid JSON: {}", e));
                let _ = write_half
                    .write_all(format!("{}\n", serde_json::to_string(&resp).unwrap()).as_bytes())
                    .await;
                return;
            }
        };

        log::info!("Command: {:?}", req);

        let is_shutdown = req.cmd == "shutdown";
        let resp = Self::process_command(&req, &clients).await;

        let json = format!("{}\n", serde_json::to_string(&resp).unwrap());
        let _ = write_half.write_all(json.as_bytes()).await;

        if is_shutdown {
            *shutdown.lock().await = true;
        }
    }

    /// Process a command and return a response
    async fn process_command(
        req: &Request,
        clients: &HashMap<String, ManagedClient>,
    ) -> Response {
        match req.cmd.as_str() {
            "status" => {
                let mut lines = vec![];
                for (name, mc) in clients {
                    let client = mc.client.lock().await;
                    let state = if client.in_call { "in call" } else { "idle" };
                    lines.push(format!(
                        "  {}: {}@{} bound={} {}",
                        name, client.username, client.domain, client.local_addr, state
                    ));
                }
                Response::ok(&format!("Accounts:\n{}", lines.join("\n")))
            }

            "register" => {
                let account_name = match &req.account {
                    Some(a) => a,
                    None => return Response::fail("'register' requires 'account' field"),
                };
                let mc = match clients.get(account_name) {
                    Some(m) => m,
                    None => return Response::fail(&format!("Account '{}' not found", account_name)),
                };
                let client = mc.client.lock().await;
                match client.register().await {
                    Ok(true) => Response::ok(&format!("'{}' registered", account_name)),
                    Ok(false) => Response::fail(&format!("'{}' registration failed", account_name)),
                    Err(e) => Response::fail(&format!("'{}' error: {}", account_name, e)),
                }
            }

            "call" => {
                let account_name = match &req.account {
                    Some(a) => a,
                    None => return Response::fail("'call' requires 'account' field"),
                };
                let target = match &req.target {
                    Some(t) => t,
                    None => return Response::fail("'call' requires 'target' field"),
                };
                let mc = match clients.get(account_name) {
                    Some(m) => m,
                    None => return Response::fail(&format!("Account '{}' not found", account_name)),
                };
                let mut client = mc.client.lock().await;
                match client.invite(target).await {
                    Ok(true) => Response::ok(&format!("'{}' calling {} - established", account_name, target)),
                    Ok(false) => Response::fail(&format!("'{}' call to {} failed", account_name, target)),
                    Err(e) => Response::fail(&format!("'{}' error: {}", account_name, e)),
                }
            }

            "hangup" => {
                let account_name = match &req.account {
                    Some(a) => a,
                    None => return Response::fail("'hangup' requires 'account' field"),
                };
                let mc = match clients.get(account_name) {
                    Some(m) => m,
                    None => return Response::fail(&format!("Account '{}' not found", account_name)),
                };
                let mut client = mc.client.lock().await;
                match client.bye().await {
                    Ok(true) => Response::ok(&format!("'{}' call ended", account_name)),
                    Ok(false) => Response::fail(&format!("'{}' no active call", account_name)),
                    Err(e) => Response::fail(&format!("'{}' error: {}", account_name, e)),
                }
            }

            "cancel" => {
                let account_name = match &req.account {
                    Some(a) => a,
                    None => return Response::fail("'cancel' requires 'account' field"),
                };
                let mc = match clients.get(account_name) {
                    Some(m) => m,
                    None => return Response::fail(&format!("Account '{}' not found", account_name)),
                };
                let client = mc.client.lock().await;
                match client.cancel().await {
                    Ok(true) => Response::ok(&format!("'{}' cancelled", account_name)),
                    Ok(false) => Response::fail(&format!("'{}' cancel failed", account_name)),
                    Err(e) => Response::fail(&format!("'{}' error: {}", account_name, e)),
                }
            }

            "play" => {
                let account_name = match &req.account {
                    Some(a) => a.clone(),
                    None => return Response::fail("'play' requires 'account' field"),
                };
                let wav_path = match &req.target {
                    Some(t) => t.clone(),
                    None => return Response::fail("'play' requires 'target' (WAV file path) field"),
                };
                let mc = match clients.get(&account_name) {
                    Some(m) => m,
                    None => return Response::fail(&format!("Account '{}' not found", account_name)),
                };
                let client = mc.client.lock().await;
                if !client.in_call {
                    return Response::fail(&format!("'{}' has no active call", account_name));
                }

                let target_addr = client.server_addr;
                let rtp_port = client.rtp_port_start;
                let codec = mc.codec;
                drop(client);

                // Read and play WAV file
                match std::fs::read(&wav_path) {
                    Ok(data) => {
                        match crate::rtp::wav::parse_wav(&data) {
                            Ok((info, samples)) => {
                                let sample_count = samples.len();
                                let sample_rate = info.sample_rate;
                                let target = format!("{}:{}", target_addr.ip(), rtp_port)
                                    .parse()
                                    .unwrap_or(target_addr);

                                tokio::spawn(async move {
                                    match crate::rtp::send_wav_rtp(
                                        &samples,
                                        sample_rate,
                                        target,
                                        0,
                                        rtp_port,
                                        codec,
                                    )
                                    .await
                                    {
                                        Ok(n) => log::info!("Sent {} RTP packets (codec={:?})", n, codec),
                                        Err(e) => log::error!("RTP send error: {}", e),
                                    }
                                });
                                Response::ok(&format!(
                                    "Playing '{}' ({} samples, {}Hz, codec={:?}) to '{}'",
                                    wav_path, sample_count, sample_rate, codec, account_name
                                ))
                            }
                            Err(e) => Response::fail(&format!("WAV parse error: {}", e)),
                        }
                    }
                    Err(e) => Response::fail(&format!("Cannot read file '{}': {}", wav_path, e)),
                }
            }

            "shutdown" => {
                Response::ok("Shutting down...")
            }

            _ => Response::fail(&format!("Unknown command: '{}'", req.cmd)),
        }
    }
}

