{"content": "//! IVR / Auto-Attendant engine
//!
//! Handles incoming calls: answer → play welcome → wait for DTMF → execute action.
//! Actions: transfer, playback sub-menus, record, hold, hangup.

use crate::rtp::codec::Codec;
use crate::rtp::receiver::{save_wav, RtpReceiver};
use crate::sip::{SipClient, SipSettings};
use crate::sip::{messages, transfer};
use anyhow::Result;
use std::collections::HashMap;
use std::net::SocketAddr;
use std::sync::Arc;
use std::time::{Duration, Instant};
use tokio::sync::Mutex;

/// IVR action after DTMF input
#[derive(Clone, Debug)]
pub enum IvrAction {
    /// Transfer to a SIP URI
    Transfer(String),
    /// Play a WAV file, then return to menu
    Playback(String),
    /// Record audio for N seconds, save to file
    Record { path: String, duration_secs: u64 },
    /// Put call on hold, then wait for another DTMF to resume
    Hold,
    /// Resume from hold
    Resume,
    /// Hang up
    Hangup,
}

/// DTMF → action mapping for a menu
pub type IvrMenu = HashMap<char, IvrAction>;

/// IVR configuration
#[derive(Clone)]
pub struct IvrConfig {
    /// Path to welcome WAV file (8kHz, 16-bit, mono PCM)
    pub welcome_file: String,
    /// Max time to wait for DTMF input (seconds)
    pub timeout_secs: u64,
    /// Max DTMF digits to collect
    pub max_digits: usize,
    /// DTMF → action map
    pub menu: IvrMenu,
    /// Default action if no DTMF or invalid input
    pub default_action: Option<IvrAction>,
}

/// Running IVR session state
pub struct IvrSession {
    config: IvrConfig,
    codec: Codec,
}

impl IvrSession {
    /// Create a new IVR session
    pub fn new(config: IvrConfig, codec: Codec) -> Self {
        IvrSession { config, codec }
    }

    /// Run the IVR loop on an answered incoming call.
    ///
    /// The caller must already have answered (200 OK sent) and received ACK.
    /// `client` is the SIP client for the account that received the call.
    /// `remote_rtp_addr` is where to send RTP (caller's RTP port).
    pub async fn run(
        &self,
        client: &Arc<Mutex<SipClient>>,
        remote_rtp_addr: SocketAddr,
        receiver: &RtpReceiver,
    ) -> Result<()> {
        // Play welcome message
        self.play_and_collect(
            client, &self.config.welcome_file, remote_rtp_addr, receiver,
        )
        .await?;

        // Main menu loop
        loop {
            let digits = self
                .collect_dtmf(receiver, self.config.timeout_secs, self.config.max_digits)
                .await;

            if digits.is_empty() {
                // Timeout — execute default action
                if let Some(ref action) = self.config.default_action {
                    self.execute_action(client, action, remote_rtp_addr, receiver)
                        .await?;
                }
                break;
            }

            // Try exact match first, then first-char match
            let action = if let Some(act) = self.config.menu.get(&digits.chars().next().unwrap()) {
                act.clone()
            } else if let Some(ref act) = self.config.default_action {
                act.clone()
            } else {
                break;
            };

            let should_break = self
                .execute_action(client, &action, remote_rtp_addr, receiver)
                .await?;
            if should_break {
                break;
            }
        }

        Ok(())
    }

    /// Play a WAV file while also collecting DTMF.
    async fn play_and_collect(
        &self,
        client: &Arc<Mutex<SipClient>>,
        wav_path: &str,
        remote_addr: SocketAddr,
        receiver: &RtpReceiver,
    ) -> Result<()> {
        let data = std::fs::read(wav_path)?;
        let (_info, samples) = crate::rtp::wav::parse_wav(&data)?;

        let client_guard = client.lock().await;
        let rtp_port = client_guard.rtp_port_start;
        let target_rate = self.codec.clock_rate();
        drop(client_guard);

        // Send audio in background
        let samples_clone = samples.clone();
        let codec = self.codec;
        let target = remote_addr;
        tokio::spawn(async move {
            let _ = crate::rtp::send_wav_rtp(
                &samples_clone,
                target_rate,
                target,
                0,
                rtp_port,
                codec,
            )
            .await;
        });

        // While audio plays, collect any DTMF
        // (DTMF collection runs in parallel via RtpReceiver background task)
        let _ = receiver; // DTMF is being collected in background
        let audio_duration = Duration::from_secs_f64(samples.len() as f64 / target_rate as f64);
        tokio::time::sleep(audio_duration).await;

        Ok(())
    }

    /// Collect DTMF digits with timeout
    async fn collect_dtmf(
        &self,
        receiver: &RtpReceiver,
        timeout_secs: u64,
        max_digits: usize,
    ) -> String {
        let deadline = Instant::now() + Duration::from_secs(timeout_secs);
        let mut all_digits = String::new();

        loop {
            let remaining = deadline.saturating_duration_since(Instant::now());
            if remaining.is_zero() {
                break;
            }

            // Poll every 200ms
            tokio::time::sleep(Duration::from_millis(200)).await;

            let new_digits = receiver.take_dtmf().await;
            all_digits.push_str(&new_digits);

            if all_digits.len() >= max_digits {
                break;
            }

            // If we got at least one digit, reset timeout briefly
            if !new_digits.is_empty() {
                // Give user more time between digits
                let digit_deadline = Instant::now() + Duration::from_secs(3);
                while Instant::now() < digit_deadline && all_digits.len() < max_digits {
                    tokio::time::sleep(Duration::from_millis(200)).await;
                    let more = receiver.take_dtmf().await;
                    if more.is_empty() {
                        break;
                    }
                    all_digits.push_str(&more);
                }
                break;
            }
        }

        log::info!("IVR collected DTMF: {:?}", all_digits);
        all_digits
    }

    /// Execute an IVR action. Returns true if the call should end.
    async fn execute_action(
        &self,
        client: &Arc<Mutex<SipClient>>,
        action: &IvrAction,
        remote_addr: SocketAddr,
        receiver: &RtpReceiver,
    ) -> Result<bool> {
        let mut client_guard = client.lock().await;

        match action {
            IvrAction::Transfer(target) => {
                log::info!("IVR: transferring to {}", target);
                let local = client_guard.local_addr_str();
                let call_id = client_guard.call_id.as_ref().cloned().unwrap_or_default();
                let remote_tag = client_guard.remote_tag.as_ref().cloned().unwrap_or_default();

                let msg = transfer::build_refer(
                    &client_guard.username,
                    &client_guard.domain,
                    target,
                    &local,
                    &client_guard.local_tag,
                    &remote_tag,
                    &call_id,
                    client_guard.next_cseq().await,
                    &client_guard.new_branch(),
                    &client_guard.settings,
                );
                drop(client_guard);
                self.send_sip(client, &msg).await?;
                Ok(true) // End IVR loop after transfer
            }

            IvrAction::Playback(path) => {
                log::info!("IVR: playing {}", path);
                drop(client_guard);
                self.play_and_collect(client, path, remote_addr, receiver)
                    .await?;
                Ok(false) // Continue IVR loop
            }

            IvrAction::Record { path, duration_secs } => {
                log::info!("IVR: recording for {}s to {}", duration_secs, path);
                drop(client_guard);

                receiver.start_recording().await;
                tokio::time::sleep(Duration::from_secs(*duration_secs)).await;
                let samples = receiver.stop_recording().await;

                save_wav(&samples, self.codec.clock_rate(), path)?;
                log::info!("IVR: recording saved to {} ({} samples)", path, samples.len());
                Ok(false)
            }

            IvrAction::Hold => {
                log::info!("IVR: putting call on hold");
                let local = client_guard.local_addr_str();
                let call_id = client_guard.call_id.as_ref().cloned().unwrap_or_default();
                let remote_tag = client_guard.remote_tag.as_ref().cloned().unwrap_or_default();
                let local_ip = client_guard.local_addr.ip().to_string();
                let rtp_port = client_guard.rtp_port_start;

                let msg = transfer::build_hold(
                    &client_guard.username,
                    &client_guard.domain,
                    &local_ip,
                    &local,
                    &client_guard.local_tag,
                    &remote_tag,
                    &call_id,
                    client_guard.next_cseq().await,
                    &client_guard.new_branch(),
                    rtp_port,
                    &client_guard.settings,
                    false, // hold
                );
                let client_clone = client.clone();
                let remote = remote_addr;
                let recv = Arc::new(receiver.clone_dtmf());
                drop(client_guard);

                self.send_sip(client, &msg).await?;

                // Wait for resume DTMF (any key)
                log::info!("IVR: waiting for DTMF to resume...");
                loop {
                    let digits = recv.take_dtmf().await;
                    if !digits.is_empty() {
                        break;
                    }
                    tokio::time::sleep(Duration::from_millis(300)).await;
                }

                // Resume
                let mut cg = client_clone.lock().await;
                let msg2 = transfer::build_hold(
                    &cg.username, &cg.domain, &cg.local_addr.ip().to_string(),
                    &cg.local_addr_str(), &cg.local_tag,
                    cg.remote_tag.as_deref().unwrap_or(""),
                    cg.call_id.as_deref().unwrap_or(""),
                    cg.next_cseq().await, &cg.new_branch(),
                    cg.rtp_port_start, &cg.settings, true, // resume
                );
                drop(cg);
                self.send_sip(&client_clone, &msg2).await?;
                Ok(false)
            }

            IvrAction::Resume => {
                // Already handled inside Hold, standalone Resume is no-op
                Ok(false)
            }

            IvrAction::Hangup => {
                log::info!("IVR: hanging up");
                let result = client_guard.bye().await;
                drop(client_guard);
                result?;
                Ok(true)
            }
        }
    }

    /// Send a SIP message through the client
    async fn send_sip(&self, client: &Arc<Mutex<SipClient>>, msg: &str) -> Result<()> {
        let client = client.lock().await;
        client.send(msg).await?;
        Ok(())
    }
}

/// Clone helper for RtpReceiver — share DTMF buffer
impl RtpReceiver {
    fn clone_dtmf(&self) -> Self {
        // We only need the shared state for DTMF
        // This is a bit hacky: we share the Arc's
        todo!("Use Arc sharing instead")
    }
}
